================================================================================
C# MCP SERVER API SUMMARY - ModelContextProtocol v1.2.0
================================================================================

REQUIRED NAMESPACES:
====================
using Microsoft.AspNetCore.Builder;              // For MapMcp()
using Microsoft.Extensions.DependencyInjection;  // For AddMcpServer(), WithTools(), WithResources()
using ModelContextProtocol.AspNetCore;            // For HttpServerTransportOptions
using ModelContextProtocol.Server;                // For attributes and MCP server types


SETUP IN Program.cs:
====================

1. ADD MCP SERVER TO DI:
   var builder = WebApplication.CreateBuilder(args);
   builder.Services
       .AddMcpServer(options =>
       {
           // options.ServerInfo = new ServerInfo { Name = "MyServer", Version = "1.0" };
       })
       .WithHttpTransport(options =>
       {
           // options.Stateless = false;  // for state management
           // options.EnableLegacySse = false;
       })
       .AddAuthorizationFilters()
       .WithTools<MyToolsClass>()
       .WithResources<MyResourcesClass>();

2. MAP MCP ENDPOINTS:
   var app = builder.Build();
   app.MapMcp("/mcp");  // Route pattern, default is ""
   app.Run();


ATTRIBUTE-BASED TOOL DEFINITION:
================================

[McpServerToolType]  // Mark class for automatic discovery
public class MyToolsClass
{
    [McpServerTool]
    public string GetWeather(string location)
    {
        return $"Weather for {location}";
    }

    [McpServerTool]
    public async Task<string> SearchDocuments(string query, int limit = 10)
    {
        // Async tools are supported
        return $"Results for {query}";
    }

    // Private methods are supported if marked with [McpServerTool]
    [McpServerTool]
    private int PrivateCalculation(int a, int b)
    {
        return a + b;
    }
}

AUTOMATIC DISCOVERY FROM ASSEMBLY:
    .WithToolsFromAssembly(Assembly.GetExecutingAssembly())


ATTRIBUTE-BASED RESOURCE DEFINITION:
====================================

[McpServerResourceType]  // Mark class for automatic discovery
public class MyResourcesClass
{
    [McpServerResource]
    public string GetDocument(string uri)
    {
        return $"Content of {uri}";
    }

    [McpServerResource]
    public List<string> ListResources()
    {
        return new List<string> { "res://doc1", "res://doc2" };
    }
}

AUTOMATIC DISCOVERY FROM ASSEMBLY:
    .WithResourcesFromAssembly(Assembly.GetExecutingAssembly())


EXTENSION METHOD SIGNATURES:
============================

DI SETUP METHODS:
─────────────────

/// Initializes the MCP server in the DI container
AddMcpServer(IServiceCollection, Action<McpServerOptions>?)
    Returns: IMcpServerBuilder

/// Sets up HTTP Streamable transport (required for ASP.NET Core)
WithHttpTransport(IMcpServerBuilder, Action<HttpServerTransportOptions>?)
    Returns: IMcpServerBuilder

/// Adds authorization filter support for [Authorize] attributes
AddAuthorizationFilters(IMcpServerBuilder)
    Returns: IMcpServerBuilder

/// Registers distributed cache for SSE resumability
WithDistributedCacheEventStreamStore(IMcpServerBuilder, Action<DistributedCacheEventStreamStoreOptions>?)
    Returns: IMcpServerBuilder


TOOL REGISTRATION METHODS:
──────────────────────────

/// Generic registration from type with attribute scanning
WithTools<TToolType>(IMcpServerBuilder, JsonSerializerOptions? = null)
    Returns: IMcpServerBuilder

/// Generic registration with specific instance
WithTools<TToolType>(IMcpServerBuilder, TToolType, JsonSerializerOptions? = null)
    Returns: IMcpServerBuilder

/// Direct tool registration
WithTools(IMcpServerBuilder, IEnumerable<McpServerTool>)
    Returns: IMcpServerBuilder

/// Type-based registration with attribute scanning
WithTools(IMcpServerBuilder, IEnumerable<Type>, JsonSerializerOptions?)
    Returns: IMcpServerBuilder

/// Assembly-wide discovery of [McpServerToolType] marked classes
WithToolsFromAssembly(IMcpServerBuilder, Assembly, JsonSerializerOptions?)
    Returns: IMcpServerBuilder


RESOURCE REGISTRATION METHODS:
──────────────────────────────

/// Generic registration from type with attribute scanning
WithResources<TResourceType>(IMcpServerBuilder)
    Returns: IMcpServerBuilder

/// Generic registration with specific instance
WithResources<TResourceType>(IMcpServerBuilder, TResourceType)
    Returns: IMcpServerBuilder

/// Direct resource registration
WithResources(IMcpServerBuilder, IEnumerable<McpServerResource>)
    Returns: IMcpServerBuilder

/// Type-based registration with attribute scanning
WithResources(IMcpServerBuilder, IEnumerable<Type>)
    Returns: IMcpServerBuilder

/// Assembly-wide discovery of [McpServerResourceType] marked classes
WithResourcesFromAssembly(IMcpServerBuilder, Assembly?)
    Returns: IMcpServerBuilder


ENDPOINT MAPPING:
─────────────────

/// Maps MCP HTTP endpoints to the application
MapMcp(IEndpointRouteBuilder, string pattern = "")
    Returns: IEndpointConventionBuilder


ATTRIBUTES:
===========

[McpServerToolAttribute]
───────────────────────
Usage: Applied to individual methods in a tool class
Target: Methods
Required: Yes, when using type-based registration
Optional: No, if providing tools directly via McpServerTool objects

Applies to:
  - Instance methods (tool will be created per invocation)
  - Static methods
  - Private methods
  - Async methods (Task<T> return types)

Example:
  [McpServerTool]
  public string MyTool(string param1, int param2)
  {
      return $"{param1}: {param2}";
  }


[McpServerToolTypeAttribute]
────────────────────────────
Usage: Applied to class containing tool methods
Target: Classes
Required: Yes, for automatic discovery via WithToolsFromAssembly()
Optional: For explicit registration, use [McpServerTool] on methods instead

Scope:
  - Discovers all methods marked with [McpServerTool]
  - Can combine multiple tool types
  - Works with WithToolsFromAssembly() for batch registration

Example:
  [McpServerToolType]
  public class MathTools
  {
      [McpServerTool]
      public int Add(int a, int b) => a + b;
  }


[McpServerResourceAttribute]
────────────────────────────
Usage: Applied to individual methods or properties providing resources
Target: Methods, Properties
Required: Yes, when using type-based registration
Optional: No, if providing resources directly via McpServerResource objects

Applies to:
  - Instance methods
  - Static methods
  - Properties (getter only)
  - Async methods

Example:
  [McpServerResource]
  public string GetDocumentContent(string uri)
  {
      return File.ReadAllText(uri);
  }

  [McpServerResource]
  public List<string> AvailableResources => new() { "file1", "file2" };


[McpServerResourceTypeAttribute]
────────────────────────────────
Usage: Applied to class containing resource methods/properties
Target: Classes
Required: Yes, for automatic discovery via WithResourcesFromAssembly()
Optional: For explicit registration, use WithResources<T>() directly

Scope:
  - Discovers all methods/properties marked with [McpServerResource]
  - Can combine multiple resource types
  - Works with WithResourcesFromAssembly() for batch registration

Example:
  [McpServerResourceType]
  public class DocumentResources
  {
      [McpServerResource]
      public string ReadFile(string path) => File.ReadAllText(path);
  }


FLUENT BUILDER PATTERN EXAMPLE:
===============================

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(serverOptions =>
    {
        serverOptions.ServerInfo = new ServerInfo 
        { 
            Name = "ComplexServer", 
            Version = "1.0.0" 
        };
    })
    .WithHttpTransport(httpOptions =>
    {
        httpOptions.Stateless = false;
        httpOptions.EnableLegacySse = true;
    })
    .AddAuthorizationFilters()
    .WithTools<MathTools>()
    .WithTools<StringTools>()
    .WithResources<DocumentResources>()
    .WithResourcesFromAssembly(Assembly.GetExecutingAssembly())
    .WithDistributedCacheEventStreamStore(cacheOptions =>
    {
        cacheOptions.StreamReaderPollingInterval = TimeSpan.FromMilliseconds(100);
    });

var app = builder.Build();
app.MapMcp("/mcp");
await app.RunAsync();


KEY CONFIGURATION OPTIONS:
==========================

HttpServerTransportOptions:
  - Stateless (bool): Enables stateless operation
  - EnableLegacySse (bool): Enables legacy HTTP with SSE transport

McpServerOptions:
  - ServerInfo (ServerInfo): Server name and version
  - MaxRequestSize: Maximum request size
  - MaxResponseSize: Maximum response size

DistributedCacheEventStreamStoreOptions:
  - Cache (IDistributedCache): Cache instance for event storage
  - EventSlidingExpiration (TimeSpan): Event cache duration
  - EventAbsoluteExpiration (TimeSpan): Absolute event expiration
  - MetadataSlidingExpiration (TimeSpan): Metadata cache duration
  - MetadataAbsoluteExpiration (TimeSpan): Absolute metadata expiration
  - StreamReaderPollingInterval (TimeSpan): Polling interval for stream readers


METHOD PARAMETER TYPES:
======================

Tools/Resources support the following parameter types in their signatures:
  - Primitive types: string, int, double, bool, etc.
  - Collections: List<T>, IEnumerable<T>, T[]
  - Objects: Custom serializable types (via JSON serialization)
  - DateTime, TimeSpan
  - Guid
  - Optional parameters (with default values)

Return types:
  - Primitive types
  - Collections
  - Objects
  - Task<T> for async operations
  - void (async as Task)


COMPLETE MINIMAL EXAMPLE:
=========================

Program.cs:
───────────
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using ModelContextProtocol.AspNetCore;
using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder();

builder.Services
    .AddMcpServer()
    .WithHttpTransport()
